const now = new Date();
const lastDay = new Date(now.getFullYear(), now.getMonth()+1, 0);
const isLastBizDay = [1,2,3,4,5].includes(now.getDay()) && (lastDay.getDate() === now.getDate() || (lastDay.getDay() === 0 && now.getDate() === lastDay.getDate()-2) || (lastDay.getDay() === 6 && now.getDate() === lastDay.getDate()-1));
if (!isLastBizDay) {
  return [{ json: { skip: true, msg: 'Not last business day of month' } }];
}
return [{ json: { skip: false, month: now.toLocaleDateString('en-GB', { month: 'long', year: 'numeric' }), month_start: new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0], today: now.toISOString().split('T')[0] } }];

const items = $input.all();

const pipeline_data = items.find(i => i.json.results)?.json?.results || [];
const subs_data = items.find(i => i.json.data?.[0]?.plan)?.json?.data || [];
const support_data = items.find(i => i.json.conversations)?.json?.conversations || [];
const targets_data = items.find(i => i.json[0]?.ARR_Target)?.json?.[0] || {};

const month_meta = $('Check Last Biz Day').first().json;

// Pipeline metrics
const open_deals = pipeline_data.filter(d => d.properties?.dealstage?.value !== 'closedwon').length;
const pipeline_value = pipeline_data.reduce((s,d) => s + parseFloat(d.properties?.amount?.value||0), 0);
const won_this_month = pipeline_data.filter(d => d.properties?.dealstage?.value === 'closedwon').reduce((s,d) => s+parseFloat(d.properties?.amount?.value||0), 0);

// Revenue metrics (from active subscriptions)
const mrr = subs_data.reduce((s,sub) => {
  const plan = sub.items?.data?.[0]?.price;
  if (!plan) return s;
  const amt = plan.recurring?.interval === 'year' ? (plan.unit_amount/100/12) : (plan.unit_amount/100);
  return s + amt;
}, 0);
const arr = mrr * 12;

// Support metrics
const support_vol = support_data.length;
const csat_items = support_data.filter(c => c.conversation_rating?.rating);
const avg_csat = csat_items.length > 0 ? (csat_items.reduce((s,c) => s + parseInt(c.conversation_rating.rating), 0) / csat_items.length).toFixed(1) : 'N/A';

// Variance calculations
const variance = (actual, target) => target > 0 ? ((actual - target) / target * 100).toFixed(1) + '%' : 'N/A';

return [{ json: {
  month: month_meta.month,
  arr: Math.round(arr), arr_target: targets_data.ARR_Target || 0, arr_variance: variance(arr, targets_data.ARR_Target),
  mrr: Math.round(mrr), pipeline_value: Math.round(pipeline_value),
  open_deals, won_this_month: Math.round(won_this_month),
  active_subs: subs_data.length,
  support_vol, avg_csat,
  generated_at: new Date().toISOString()
}}];

